import os
import pip

def install_dependencies():
    requirements = "requirements.txt"
    upgrade = True
    hash_verification = False

    with open(requirements, "r") as f:
        for line in f:
            package = line.strip()
            if package and not package.startswith("#"):
                pip.main(["install", "-r", requirements, "--upgrade", "--no-hash-check"])